CREATE VIEW `ads_sensors_production_operationpositionclick_view` (`dt` COMMENT "分区日期", `id` COMMENT "nvl(rid,track_id)", `track_id`, `rid` COMMENT "记录ID", `event_tm` COMMENT "事件时间", `device_id` COMMENT "设备id", `login_id` COMMENT "login_id", `identity_login_id` COMMENT "identity_login_id", `device_lang` COMMENT "设备语言", `event` COMMENT "事件", `distinct_id` COMMENT "distinct_id", `identity_user_id` COMMENT "identity_userid", `app_product_id` COMMENT "包体ID", `send_id` COMMENT "转化来源", `app_core_ver` COMMENT "core", `app_channel` COMMENT "渠道编号", `app_product_x` COMMENT "应用程序ID", `app_lang_id` COMMENT "界面语言", `page_name` COMMENT "页面名称", `page_id` COMMENT "页面ID", `element_name` COMMENT "控件名称", `element_id` COMMENT "控件ID", `element_type` COMMENT "控件类型", `activity_id` COMMENT "活动id", `parent_group_id` COMMENT "用户集合ID", `group_id` COMMENT "用户分组ID", `countdown` COMMENT "倒计时标签时长", `event_strategy_id` COMMENT "策略id", `element_content` COMMENT "点击元素内容", `start_type` COMMENT "启动类型", `project_id` COMMENT "5 阅读 8 短剧", `activity_link` COMMENT "活动链路", `pay_link` COMMENT "支付链路", `reg_language` COMMENT "注册时语言", `os` COMMENT "操作系统", `etl_tm` COMMENT "清洗时间")
COMMENT "event=operationPositionClick 特定运营位点击时上报" AS SELECT `ods_log`.`a`.`dt`, `ods_log`.`a`.`id`, `ods_log`.`a`.`track_id`, `ods_log`.`a`.`rid`, `ods_log`.`a`.`event_tm`, `ods_log`.`a`.`device_id`, `ods_log`.`a`.`login_id`, `ods_log`.`a`.`identity_login_id`, `ods_log`.`a`.`device_lang`, `ods_log`.`a`.`event`, `ods_log`.`a`.`distinct_id`, `ods_log`.`a`.`identity_user_id`, `ods_log`.`a`.`app_product_id`, `ods_log`.`a`.`send_id`, `ods_log`.`a`.`app_core_ver`, `ods_log`.`a`.`app_channel`, `ods_log`.`a`.`app_product_x`, `ods_log`.`a`.`app_lang_id`, `ods_log`.`a`.`page_name`, `ods_log`.`a`.`page_id`, `ods_log`.`a`.`element_name`, `ods_log`.`a`.`element_id`, `ods_log`.`a`.`element_type`, `ods_log`.`a`.`activity_id`, `ods_log`.`a`.`parent_group_id`, `ods_log`.`a`.`group_id`, `ods_log`.`a`.`countdown`, `ods_log`.`a`.`event_strategy_id`, `ods_log`.`a`.`element_content`, `ods_log`.`a`.`start_type`, `ods_log`.`a`.`project_id`, `ods_log`.`a`.`activity_link`, `ods_log`.`a`.`pay_link`, `dim`.`b`.`current_language2` AS `reg_language`, `ods_log`.`a`.`os`, `ods_log`.`a`.`etl_tm`
FROM `ods_log`.`ods_sensors_cd_video_production_operationPositionClick` AS `a` LEFT OUTER JOIN `dim`.`dim_user_account_info_view` AS `b` ON (`ods_log`.`a`.`app_product_id` = `dim`.`b`.`product_id`) AND (`ods_log`.`a`.`identity_user_id` = `dim`.`b`.`id`)
WHERE `ods_log`.`a`.`project_id` = 5;